import { useState } from "react";
import axios from "axios";
import Navbar from "../components/Navbar";

export default function CustomerDashboard() {

  const [workers, setWorkers] = useState([]);

  const [search, setSearch] = useState("");

  const [searched, setSearched] = useState(false);

  const [date, setDate] = useState("");

  const [time1, setTime1] = useState("");

  const [time2, setTime2] = useState("");

  const [time3, setTime3] = useState("");


  // SEARCH WORKERS

  const searchWorkers = async () => {

    try {

      const res = await axios.get(
        "http://localhost:5000/api/auth/workers"
      );

      const filtered = res.data.filter(worker =>

        worker.skills?.some(skill =>

          skill.toLowerCase().includes(
            search.toLowerCase()
          )
        )
      );

      setWorkers(filtered);

      setSearched(true);

    } catch (err) {

      alert("Failed");
    }
  };


  // SEND REQUEST

  const sendRequest = async (worker) => {

    const user =
      JSON.parse(localStorage.getItem("user"));

    try {

      await axios.post(
        "http://localhost:5000/api/request/send",
        {

          customerName: user.name,

          labourId: worker._id,

          labourName: worker.name,

          workType: search,

          date: date,

          timings: [
            time1,
            time2,
            time3
          ]
        }
      );

      alert("Request Sent");

    } catch (err) {

      alert("Failed");
    }
  };

  return (

    <div style={styles.page}>

      <Navbar />

      <div style={styles.container}>

        <h1 style={styles.heading}>
          Find Workers
        </h1>

        {/* SEARCH */}

        <div style={styles.searchCard}>

          <input
            style={styles.input}
            placeholder="Search work type..."
            value={search}
            onChange={(e) =>
              setSearch(e.target.value)
            }
          />

          <input
            type="date"
            style={styles.input}
            onChange={(e) =>
              setDate(e.target.value)
            }
          />

          <select
            style={styles.input}
            onChange={(e) =>
              setTime1(e.target.value)
            }
          >
            <option>Time Slot 1</option>
            <option>9 AM - 11 AM</option>
            <option>11 AM - 1 PM</option>
            <option>2 PM - 4 PM</option>
          </select>

          <select
            style={styles.input}
            onChange={(e) =>
              setTime2(e.target.value)
            }
          >
            <option>Time Slot 2</option>
            <option>9 AM - 11 AM</option>
            <option>11 AM - 1 PM</option>
            <option>2 PM - 4 PM</option>
          </select>

          <select
            style={styles.input}
            onChange={(e) =>
              setTime3(e.target.value)
            }
          >
            <option>Time Slot 3</option>
            <option>9 AM - 11 AM</option>
            <option>11 AM - 1 PM</option>
            <option>2 PM - 4 PM</option>
          </select>

          <button
            style={styles.searchBtn}
            onClick={searchWorkers}
          >
            Search
          </button>

        </div>

        {/* NO WORKERS */}

        {searched && workers.length === 0 && (

          <p>No workers found</p>

        )}

        {/* WORKERS */}

        <div style={styles.grid}>

          {workers.map(worker => (

            <div
              key={worker._id}
              style={styles.card}
            >

              <h2 style={styles.name}>
                {worker.name}
              </h2>

              <p>
                {worker.skills?.join(", ")}
              </p>

              <p>
                📍 {worker.city}, {worker.area}
              </p>

              <p>
                📞 {worker.phone}
              </p>

              <p style={styles.price}>
                ₹ {worker.price}
              </p>

              <button
                style={styles.requestBtn}
                onClick={() =>
                  sendRequest(worker)
                }
              >
                Send Request
              </button>

            </div>

          ))}

        </div>

      </div>

    </div>
  );
}

const styles = {

  page: {
    minHeight: "100vh",
    background: "#f5f7fb",
    fontFamily: "Arial"
  },

  container: {
    padding: "40px 60px"
  },

  heading: {
    marginBottom: "25px"
  },

  searchCard: {
    background: "white",
    padding: "25px",
    borderRadius: "14px",
    display: "grid",
    gridTemplateColumns:
      "repeat(auto-fit,minmax(180px,1fr))",
    gap: "15px",
    marginBottom: "35px"
  },

  input: {
    padding: "14px",
    borderRadius: "10px",
    border: "1px solid #ddd"
  },

  searchBtn: {
    background: "#2563eb",
    color: "white",
    border: "none",
    borderRadius: "10px",
    cursor: "pointer"
  },

  grid: {
    display: "grid",
    gridTemplateColumns:
      "repeat(auto-fit,minmax(280px,1fr))",
    gap: "20px"
  },

  card: {
    background: "white",
    padding: "24px",
    borderRadius: "16px",
    boxShadow:
      "0 4px 12px rgba(0,0,0,0.05)"
  },

  name: {
    marginBottom: "12px"
  },

  price: {
    marginTop: "10px",
    fontWeight: "bold",
    color: "#2563eb"
  },

  requestBtn: {
    width: "100%",
    marginTop: "20px",
    background: "#2563eb",
    color: "white",
    border: "none",
    padding: "13px",
    borderRadius: "10px",
    cursor: "pointer"
  }

};
